VALUES
  ('real-estate-moex-02372', 'real-estate', 'real-estate-moex-098-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '住戶積欠應繳納之管理費用達相當金額，經定相當期間催告仍不給付者，管理負責人或管理委員會經訴 請法院命其給付應繳之金額，並於強制執行後住戶再度積欠金額達其區分所有權總價的多少百分比，管 理負責人或管理委員會得依區分所有權人會議之決議，訴請法院強制其遷離？', '["百分之二十", "百分之十", "百分之五", "百分之一"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "e119da536ab8", "answer_pdf_sha1": "b6fab8935bc8", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "601", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "不動產經紀相關法規概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 10, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02373', 'real-estate', 'real-estate-moex-098-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '下列有關於消費者權益受損所提出消費訴訟的敘述，何者錯誤？', '["因企業經營者之故意所致之損害，消費者得請求損害額三倍以下之懲罰性賠償金", "但因過失所致之損害，得請求損害額一倍以下之懲罰性賠償金", "消費訴訟，得由消費關係發生地之法院管轄", "消費者保護法有關於懲罰性賠償金的請求須明訂於契約之中，消費者始得請求"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "e119da536ab8", "answer_pdf_sha1": "b6fab8935bc8", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "601", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "不動產經紀相關法規概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 11, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02374', 'real-estate', 'real-estate-moex-098-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '由區分所有權人會議決議或管理負責人或管理委員會僱傭或委任而執行建築物管理維護事務之公寓大廈 管理服務人員或管理維護公司，稱為：', '["管理負責人", "管理服務人", "管理人員", "主任委員"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "e119da536ab8", "answer_pdf_sha1": "b6fab8935bc8", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "601", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "不動產經紀相關法規概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 12, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02375', 'real-estate', 'real-estate-moex-098-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '一樓住戶需要進入二樓住戶的室內修繕漏水的管線，下列敘述何者錯誤？', '["二樓住戶的室內為專用部分的產權，二樓住戶得拒絕一樓住戶進入", "若修繕漏水的管線，必須使用共用部分時，應經管理委員會之同意", "若一樓住戶入二樓住戶的室內修繕漏水的管線應擇其損害最少之處所及方法為之", "若一樓住戶進入二樓住戶的室內修繕漏水的管線導致其他損害發生，一樓住戶應修復或補償所生損害"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "e119da536ab8", "answer_pdf_sha1": "b6fab8935bc8", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "601", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "不動產經紀相關法規概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 13, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02376', 'real-estate', 'real-estate-moex-098-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '李先生在富貴社區居住20年，每年均按月繳交管理費納入公共基金，今年李先生因搬家而出售位於該社 區的房地產給陳先生，請問李先生對於該公共基金的權利應如何處理？', '["用剩的部分退回給李先生", "抵繳李先生應負擔的搬家費用", "抵繳李先生應負擔的銀行貸款", "隨著該房地產移轉給陳先生"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "e119da536ab8", "answer_pdf_sha1": "b6fab8935bc8", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "601", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "不動產經紀相關法規概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 14, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02377', 'real-estate', 'real-estate-moex-098-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '理想社區98年1月召開區分所有權人會議之後，改選委員成立新的管理委員會，若97年的管理委員會 拒絕移交公共基金收支帳冊，經催告於幾日內仍不公告或移交時，得報請主管機關或訴請法院命其移交？', '["七日", "十日", "十五日", "三十日"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "e119da536ab8", "answer_pdf_sha1": "b6fab8935bc8", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "601", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "不動產經紀相關法規概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 15, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02378', 'real-estate', 'real-estate-moex-098-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '召開區分所有權人會議的臨時會議，除了發生重大事故有及時處理之必要以外，還可以由區分所有權人 人數多少比例以上及其區分所有權比例合計多少比例以上，以書面載明召集之目的及理由請求召集？', '["二分之一，三分之二", "三分之一，三分之一", "五分之一，五分之一", "五分之一，五分之三"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "e119da536ab8", "answer_pdf_sha1": "b6fab8935bc8", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "601", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "不動產經紀相關法規概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 16, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02379', 'real-estate', 'real-estate-moex-098-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '例行性的區分所有權人會議的開會內容，召集人應於開會的幾天前以書面載明通知各區分所有權人？', '["五日", "七日", "十日", "三十日"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "e119da536ab8", "answer_pdf_sha1": "b6fab8935bc8", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "601", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "不動產經紀相關法規概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 17, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02380', 'real-estate', 'real-estate-moex-098-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '安家社區欲在公寓大廈樓頂讓電信業者架設大哥大基地台，增加社區公共基金之收入，請問應依下列何 種程序辦理始生效力？', '["管理委員會決議即可", "區分所有權人會議之決議即可", "區分所有權人會議決議，並應經頂層區分所有權人同意，頂層住戶得參加區分所有權人會議陳述意見", "區分所有權人會議決議，並應經頂層區分所有權人同意，並層報法院備查"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "e119da536ab8", "answer_pdf_sha1": "b6fab8935bc8", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "601", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "不動產經紀相關法規概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 18, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02381', 'real-estate', 'real-estate-moex-098-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '從事公寓大廈管理維護業務之管理維護公司之管理服務人員沒有領得中央主管機關的認可證，而接受公 寓大廈管理委員會之委任執行公寓大廈管理維護服務業務者，除了由直轄市、縣（市）主管機關勒令其 停止執行業務以外，並處多少罰鍰？', '["新臺幣四萬元以上二十萬元以下", "新臺幣二萬元以上十萬元以下", "新臺幣三千元以上一萬五千元以下", "新臺幣一千元以上五千元以下"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "e119da536ab8", "answer_pdf_sha1": "b6fab8935bc8", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "601", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "不動產經紀相關法規概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 19, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL)
